     // FIFO to maintain response ordering
     reg [FIFO_ADDR_WIDTH+1-1:0] fifo_wr_ptr_reg = 0;
     reg [FIFO_ADDR_WIDTH+1-1:0] fifo_rd_ptr_reg = 0;
+    wire [FIFO_ADDR_WIDTH+1-1:0] fifo_rd_ptr_inc = fifo_rd_ptr_reg + 1;
